import AppKit

/// The Mac Clean **menu-bar widget** icon: the user-supplied vacuum
/// (Downloads/vacuum.png), rendered white on the brand purple-gradient
/// squircle so it matches the app icon's background and stays legible at
/// 18px. Embedded as base64 (128px source — ample for an 18-30px icon)
/// so it loads identically under `swift run` and inside the DMG.
///
/// ONLY the menu-bar widget icon. The main app icon
/// (Resources/AppIcon.icns) is intentionally left untouched.
enum VacuumAsset {
    static let image: NSImage = {
        let b64 = ""
        guard let data = Data(base64Encoded: b64), let img = NSImage(data: data) else {
            return NSImage(systemSymbolName: "wand.and.sparkles", accessibilityDescription: "Mac Clean") ?? NSImage()
        }
        return img
    }()
}
